package renovate

import (
	"github.com/giantswarm/devctl/v8/pkg/gen/input"
	"github.com/giantswarm/devctl/v8/pkg/gen/input/renovate/internal/file"
	"github.com/giantswarm/devctl/v8/pkg/gen/input/renovate/internal/params"
)

type Config struct {
	Interval string
	Language string
	// CircleCIGenerated, when true, disables Renovate's giantswarm/architect orb
	// updates because the repo's .circleci/config.yml (and the orb version it
	// pins) is generated by `devctl gen circleci`.
	CircleCIGenerated bool
}

type Renovate struct {
	params params.Params
}

func New(config Config) (*Renovate, error) {
	w := &Renovate{
		params: params.Params{
			Dir: "",

			Interval:          config.Interval,
			Language:          config.Language,
			CircleCIGenerated: config.CircleCIGenerated,
		},
	}

	return w, nil
}

func (d *Renovate) CreateRenovate() input.Input {
	return file.NewCreateRenovateInput(d.params)
}
